fn solve(n: i64) -> Vec<i64> {
    // A hash map to store the sum as the key, and a vector of pairs (a, b) 
    // that result in this sum as the value.
    let mut sums: HashMap<i64, Vec<(i64, i64)>> = HashMap::new();

    // Since x = a^3 + b^3 and a, b are positive integers, 
    // and x <= n, we have a^3 < n and b^3 < n.
    // The maximum value for a or b is less than or equal to the cube root of n.
    // Since n <= 10^9, cube_root(10^9) = 1000.

    // We iterate 'a' from 1 up to a maximum value such that a^3 < n.
    // Since a <= b, we only need to iterate 'b' from 'a' up to a maximum value such that a^3 + b^3 <= n.

    // Maximum possible value for a is when a^3 + a^3 = 2*a^3 <= n, so a <= (n/2)^(1/3)
    // A safe upper bound for 'a' is ceil((n/2)^(1/3)). Since n <= 10^9, max a is around 793.
    let max_a_approx = (n as f64 / 2.0).powf(1.0 / 3.0) as i64 + 2;

    for a in 1..=max_a_approx {
        let a_cubed = a * a * a;

        // Maximum possible value for b such that a^3 + b^3 <= n
        // b^3 <= n - a^3
        // b <= (n - a^3)^(1/3)
        if a_cubed >= n {
            break; // If a^3 itself is >= n, no sum a^3 + b^3 (with b>=a>=1) can be <= n
        }

        let max_b_cubed = n - a_cubed;
        let max_b = (max_b_cubed as f64).powf(1.0 / 3.0).ceil() as i64;

        // Start b from a because of the condition a <= b
        let start_b = a;

        for b in start_b..=max_b {
            let b_cubed = b * b * b;
            let sum = a_cubed + b_cubed;

            if sum > n {
                // Since b is increasing, further sums will also exceed n
                break;
            }

            // Store the pair (a, b) for this sum
            sums.entry(sum).or_insert_with(Vec::new).push((a, b));
        }
    }

    // Collect all "good integers"
    let mut good_integers: Vec<i64> = Vec::new();

    for (sum, pairs) in sums {
        // A number is "good" if there are at least two *different* pairs (a, b).
        // Since we enforce a <= b, two pairs are different if they are not identical.
        // If the vector contains two or more elements, it means at least two ways to form the sum.
        if pairs.len() >= 2 {
            good_integers.push(sum);
        }
    }

    // Sort the results in ascending order
    good_integers.sort_unstable();

    good_integers
