    // Use a HashMap to store the sums found and how many ways each sum is achieved.
    // Key: x = a^3 + b^3
    // Value: count of distinct pairs (a, b) that produce x.
    let mut sums: HashMap<i64, i32> = HashMap::new();

    for a in 1..=max_a {
        // 'b' must satisfy b >= a and a^3 + b^3 <= n.
        // b^3 <= n - a^3
        let a_cubed = a * a * a;
        if a_cubed >= n {
            break; // If a^3 itself is already too large (though this should be caught by max_a if we were more precise)
        }

        let remaining_n = n - a_cubed;

        // Maximum b such that b^3 <= remaining_n
        // b_max = floor((n - a^3)^(1/3))
        let max_b_f64 = (remaining_n as f64).powf(1.0/3.0);
        let max_b = max_b_f64.floor() as i64;

        // b must be at least 'a'
        let start_b = a;

        for b in start_b..=max_b {
            let b_cubed = b * b * b;
            let x = a_cubed + b_cubed;

            // Since we calculated max_b based on x <= n, this check is technically redundant but safe.
            if x > n {
                break; 
            }

            // Increment the count for this sum x
            *sums.entry(x).or_insert(0) += 1;
        }
    }

    // Collect all "good integers" (those with count >= 2)
    let mut good_integers: Vec<i64> = Vec::new();
    for (&x, &count) in sums.iter() {
        if count >= 2 {
            good_integers.push(x);
        }
    }

    // Sort the results in ascending order
    good_integers.sort_unstable();

    good_integers
}
